namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Code { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = "";
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string Instructor { get; set; } = "";
    public string InstructorBio { get; set; } = "";
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public int CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and software systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Instructor = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published extensively on CS education pedagogy.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms).", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", Instructor = "Dr. James Liu", InstructorBio = "Dr. Liu's research focuses on algorithm optimization and computational complexity theory." },
        new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", Code = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transaction management, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", Instructor = "Prof. Maria Garcia", InstructorBio = "Prof. Garcia spent 10 years in industry building distributed database systems before joining academia.", IsFeatured = true },
        new() { Id = 4, DepartmentId = 1, DepartmentCode = "CS", Code = "CS 420", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, model evaluation, and practical applications using modern frameworks.", Credits = 4, Schedule = "Tue/Thu 1:00–2:30 PM", Instructor = "Dr. Alex Rivera", InstructorBio = "Dr. Rivera leads the university's AI research lab and has published over 50 papers in top ML conferences." },
        new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Instructor = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible and engaging.", IsFeatured = true },
        new() { Id = 6, DepartmentId = 2, DepartmentCode = "MATH", Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations with applications.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", Instructor = "Dr. Emily Walsh", InstructorBio = "Dr. Walsh specializes in applied linear algebra and numerical methods." },
        new() { Id = 7, DepartmentId = 2, DepartmentCode = "MATH", Code = "MATH 301", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Instructor = "Dr. David Park", InstructorBio = "Dr. Park's research bridges statistics and data science, with applications in public health." },
        new() { Id = 8, DepartmentId = 3, DepartmentCode = "PHYS", Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Lab Thu 2:00–4:00 PM", Instructor = "Dr. Lisa Nguyen", InstructorBio = "Dr. Nguyen's research in experimental physics has been featured in Nature and Science." },
        new() { Id = 9, DepartmentId = 3, DepartmentCode = "PHYS", Code = "PHYS 201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM + Lab Fri 1:00–3:00 PM", Instructor = "Dr. Mark Thompson", InstructorBio = "Dr. Thompson has contributed to CERN research projects and teaches with a focus on real-world applications." },
        new() { Id = 10, DepartmentId = 4, DepartmentCode = "ENG", Code = "ENG 101", Title = "Composition & Rhetoric", Description = "Develop critical reading, analytical writing, and argumentation skills through diverse texts and writing assignments.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Instructor = "Prof. Rachel Adams", InstructorBio = "Prof. Adams is a published author and writing consultant with expertise in academic discourse.", IsFeatured = true },
        new() { Id = 11, DepartmentId = 4, DepartmentCode = "ENG", Code = "ENG 250", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, examining major movements and authors.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", Instructor = "Dr. Michael Brown", InstructorBio = "Dr. Brown is a specialist in 20th-century American fiction and has authored three books on the topic." },
        new() { Id = 12, DepartmentId = 5, DepartmentCode = "HIST", Code = "HIST 101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistory through the late medieval period, covering major cultures and transformations.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", Instructor = "Dr. Patricia Moore", InstructorBio = "Dr. Moore is an archaeologist and historian specializing in ancient Mediterranean civilizations." },
        new() { Id = 13, DepartmentId = 5, DepartmentCode = "HIST", Code = "HIST 220", Title = "Modern European History", Description = "Europe from the Enlightenment to the present: revolutions, industrialization, world wars, and the European Union.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", Instructor = "Dr. Thomas Wright", InstructorBio = "Dr. Wright has published extensively on 19th-century European political movements.", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

