arguments.file_text:
@page "/"
@inject CourseCatalog.Services.CatalogService CatalogService

<PageTitle>Home - University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-5">Welcome to the University Course Catalog</h1>
    <p class="lead text-muted">Browse departments, explore courses, and submit your enrollment request.</p>
</div>

<section class="mb-5">
    <h2>Featured Courses</h2>
    <div class="row g-3">
        @foreach (var course in featuredCourses)
        {
            <div class="col-md-6 col-lg-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@course.Code</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                        <p class="card-text small">@course.Credits credits &middot; @course.Instructor</p>
                        <a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section>
    <h2>Departments</h2>
    <div class="row g-3">
        @foreach (var dept in departments)
        {
            <div class="col-md-6 col-lg-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@dept.Name</h5>
                        <p class="card-text small text-muted">@dept.Description</p>
                        <a href="/courses?departmentId=@dept.Id" class="btn btn-sm btn-outline-secondary">
                            Browse @dept.Code Courses
                        </a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

@code {
    private List<CourseCatalog.Models.Course> featuredCourses = [];
    private List<CourseCatalog.Models.Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@inject CourseCatalog.Services.CatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control"
               placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentCode</td>
                        <td>@course.Credits</td>
                        <td>@course.Instructor</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<CourseCatalog.Models.Course> courses = [];
    private List<CourseCatalog.Models.Department> departments = [];

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@inject CourseCatalog.Services.CatalogService CatalogService

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <div class="alert alert-warning">Course not found.</div>
    <a href="/courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <PageTitle>@course.Code - @course.Title</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code: @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Instructor</h4>
            <p><strong>@course.Instructor</strong></p>
            <p class="text-muted">@course.InstructorBio</p>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <ul class="list-unstyled">
                        <li class="mb-2"><strong>Credits:</strong> @course.Credits</li>
                        <li class="mb-2"><strong>Schedule:</strong> @course.Schedule</li>
                        <li class="mb-2"><strong>Department:</strong> @course.DepartmentCode</li>
                    </ul>
                    <a href="/enroll?courseId=@course.Id" class="btn btn-primary w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private CourseCatalog.Models.Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@inject CourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p class="text-muted">Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Your enrollment request has been received. You will be notified of your enrollment status.</p>
        <a href="/courses" class="btn btn-outline-success">Browse More Courses</a>
    </div>
}
else
{
    @if (error)
    {
        <div class="alert alert-danger">Please fill in all fields correctly.</div>
    }

    <form method="post" class="col-md-8">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName"
                   class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId"
                   class="form-control" placeholder="e.g., STU-2026-001" required />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">
                        @course.Code - @course.Title
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        <a href="/courses" class="btn btn-link">Cancel</a>
    </form>
