arguments.new_str:
@page "/enroll"
@inject CourseCatalog.Services.CatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p class="text-muted">Submit your enrollment request below. You will receive confirmation via your university email.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Your enrollment request has been received. You will be notified of your enrollment status.</p>
        <a href="/courses" class="btn btn-outline-success">Browse More Courses</a>
    </div>
}
else
{
    @if (error)
    {
        <div class="alert alert-danger">Please fill in all fields correctly.</div>
    }

    <form method="post" class="col-md-8">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName"
                   class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId"
                   class="form-control" placeholder="e.g., STU-2026-001" required />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">
                        @course.Code - @course.Title
                    </option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        <a href="/courses" class="btn btn-link">Cancel</a>
    </form>
}

@code {
    [SupplyParameterFromForm] public CourseCatalog.Models.EnrollmentRequest? Model { get; set; }
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<CourseCatalog.Models.Course> courses = [];
    private bool submitted;
    private bool error;

    protected override void OnInitialized()
    {
        Model ??= new();
        courses = CatalogService.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }

        // If Model was supplied from form, process the submission
        if (!string.IsNullOrEmpty(Model.StudentName) || !string.IsNullOrEmpty(Model.StudentId))
        {
            if (CatalogService.SubmitEnrollmentRequest(Model))
            {
                submitted = true;
            }
            else
            {
                error = true;
            }
        }
    }
}

